import React from 'react';
import { useCart } from '../context/CartContext';
import { Trash2, Plus, Minus, ShoppingBag, ArrowRight, Store } from 'lucide-react';

const Carrito = ({ onCheckout }) => {
    const { cart, removeFromCart, updateQuantity, total, clearCart } = useCart();

    if (cart.length === 0) {
        return (
            <div style={emptyCartStyle}>
                <ShoppingBag size={60} color="#cbd5e1" />
                <h3 style={{ color: '#64748b', marginTop: '20px' }}>Tu carrito está vacío</h3>
                <p style={{ color: '#94a3b8' }}>¡Busca las mejores ofertas en el radar!</p>
            </div>
        );
    }

    return (
        <div style={cartContainer}>
            <div style={headerStyle}>
                <h2 style={{ margin: 0 }}>Tu Pedido</h2>
                <button onClick={clearCart} style={btnClear}>Vaciar</button>
            </div>

            <div style={itemsList}>
                {cart.map((item) => (
                    <div key={item._id} style={itemCard}>
                        <img 
                            src={item.imagenUrl || "https://via.placeholder.com/150"} 
                            alt={item.producto} 
                            style={miniImg} 
                        />
                        
                        <div style={infoCol}>
                            <div style={localLabel}>
                                <Store size={10} />
                                <span>{item.local?.nombre || 'Local'}</span>
                            </div>
                            <h4 style={prodName}>{item.producto}</h4>
                            <span style={priceTag}>${item.precioNuevo}</span>
                        </div>

                        <div style={controls}>
                            <button 
                                onClick={() => updateQuantity(item._id, item.cantidad - 1)}
                                style={qtyBtn}
                                disabled={item.cantidad <= 1}
                            >
                                <Minus size={14} />
                            </button>
                            <span style={qtyNumber}>{item.cantidad}</span>
                            <button 
                                onClick={() => {
                                    if(item.cantidad < item.stock) {
                                        updateQuantity(item._id, item.cantidad + 1);
                                    } else {
                                        alert("No hay más stock disponible");
                                    }
                                }}
                                style={qtyBtn}
                            >
                                <Plus size={14} />
                            </button>
                            <button onClick={() => removeFromCart(item._id)} style={btnDel}>
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            <div style={summaryCard}>
                <div style={summaryRow}>
                    <span>Subtotal</span>
                    <span>${total}</span>
                </div>
                <div style={summaryRow}>
                    <span>Envío / Servicio</span>
                    <span style={{ color: '#22c55e', fontWeight: 'bold' }}>Bonificado</span>
                </div>
                <div style={divider} />
                <div style={totalRow}>
                    <span>Total a Pagar</span>
                    <span>${total}</span>
                </div>

                <button 
                    onClick={onCheckout} // Llamamos a la función recibida por props
                    style={btnCheckout}
                >
                    Confirmar Pedido <ArrowRight size={18} />
                </button>
            </div>
        </div>
    );
};

// --- ESTILOS ---
const cartContainer = { padding: '10px', maxWidth: '500px', margin: '0 auto' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const btnClear = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 'bold' };
const itemsList = { display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '30px' };
const itemCard = { display: 'flex', alignItems: 'center', background: 'white', padding: '12px', borderRadius: '16px', border: '1px solid #e2e8f0', gap: '12px' };
const miniImg = { width: '60px', height: '60px', borderRadius: '10px', objectFit: 'cover', background: '#f8fafc' };
const infoCol = { flex: 1 };
const localLabel = { display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.65rem', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '4px' };
const prodName = { margin: '0 0 4px 0', fontSize: '0.9rem', color: '#1e293b' };
const priceTag = { fontWeight: '800', color: '#e67e22', fontSize: '1rem' };
const controls = { display: 'flex', alignItems: 'center', gap: '8px' };
const qtyBtn = { width: '28px', height: '28px', borderRadius: '8px', border: '1px solid #e2e8f0', background: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const qtyNumber = { fontSize: '0.9rem', fontWeight: 'bold', minWidth: '20px', textAlign: 'center' };
const btnDel = { marginLeft: '5px', color: '#cbd5e1', cursor: 'pointer', border: 'none', background: 'none' };
const summaryCard = { background: '#1e293b', padding: '25px', borderRadius: '24px', color: 'white' };
const summaryRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '10px', fontSize: '0.9rem', opacity: 0.9 };
const divider = { height: '1px', background: 'rgba(255,255,255,0.1)', margin: '15px 0' };
const totalRow = { display: 'flex', justifyContent: 'space-between', fontSize: '1.2rem', fontWeight: '800', marginBottom: '20px' };
const btnCheckout = { width: '100%', padding: '15px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', fontSize: '1rem' };
const emptyCartStyle = { textAlign: 'center', padding: '100px 20px' };

export default Carrito;
